mapper.select:
/* wms-master-eqmgmt-sql-oracle.xml - selectEqMgmtDuplicateCount */
SELECT COUNT(*)
  FROM TWORK_MST_EQ
 WHERE CTKEY = #{ctkey}
   AND EQNM = #{eqnm}

mapper.insert:
/* wms-master-eqmgmt-sql-oracle.xml - insertEqMgmt */
INSERT INTO TWORK_MST_EQ (
	   CTKEY
	 , EQNM
	 , EQDIVCD
	 , EQBARCODE
	 , MODELNO
	 , MODELSERIALNO
	 , PRDCTCPNM
	 , PRDCTCPTELNO
	 , SALECPNM
	 , SALECPTELNO
	 , INSDAY
	 , OPERSTARTDAY
	 , PICH
	 , SUBPICH
	 , INSERTDATE
	 , INSERTURKEY
	 , UPDATEDATE
	 , UPDATEURKEY
     )
VALUES (
	   #{ctkey}
	 , #{eqnm}
	 , #{eqdivcd}
	 , #{eqbarcode}
	 , #{modelno}
	 , #{modelserialno}
	 , #{prdctcpnm}
	 , #{prdctcptelno}
	 , #{salecpnm}
	 , #{salecptelno}
	 , #{insday}
	 , #{operstartday}
	 , #{pich}
	 , #{subpich}
	 , TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS')
	 , #{surkey}
	 , TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS')
	 , #{surkey}
	 )

mapper.update:
/* wms-master-eqmgmt-sql-oracle.xml - updateEqMgmt */
UPDATE TWORK_MST_EQ
   SET MODELNO = #{modelno}
	 , MODELSERIALNO = #{modelserialno}
	 , PRDCTCPNM = #{prdctcpnm}
	 , PRDCTCPTELNO = #{prdctcptelno}
	 , SALECPNM = #{salecpnm}
	 , SALECPTELNO = #{salecptelno}
	 , INSDAY = #{insday}
	 , OPERSTARTDAY = #{operstartday}
	 , PICH = #{pich}
	 , SUBPICH = #{subpich}
	 , UPDATEDATE = TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS')
	 , UPDATEURKEY = #{surkey}
 WHERE CTKEY = #{ctkey}
   AND EQNM = #{eqnm}

mapper.delete:
/* wms-master-eqmgmt-sql-oracle.xml - deleteEqMgmt */
DELETE
  FROM TWORK_MST_EQ
 WHERE CTKEY = #{ctkey}
   AND EQNM = #{eqnm}
